// Validate and normalise publish payload
const _raw = $input.first().json;
const input = _raw.body ?? _raw;
const required = ['platform', 'text', 'postId', 'sheetRowId', 'callbackUrl'];
for (const field of required) {
  if (!input[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

const PLATFORMS = ['twitter', 'threads', 'instagram', 'facebook', 'skool'];
if (!PLATFORMS.includes(input.platform)) {
  throw new Error(`Invalid platform: ${input.platform}. Must be one of: ${PLATFORMS.join(', ')}`);
}

// Build full post text including hashtags
const hashtags = Array.isArray(input.hashtags) ? input.hashtags : [];
const hashtagStr = hashtags.map(h => h.startsWith('#') ? h : `#${h}`).join(' ');
const fullText = hashtags.length > 0 ? `${input.text}\n\n${hashtagStr}` : input.text;

return [{
  json: {
    platform: input.platform,
    text: input.text,
    fullText,
    hashtags,
    imageUrl: input.imageUrl || null,
    scheduledAt: input.scheduledAt || null,
    sheetRowId: String(input.sheetRowId),
    postId: String(input.postId),
    callbackUrl: input.callbackUrl,
    firstComment: input.firstComment || null
  }
}];

// Merge tweet body with media_id
const validateData = $('Code - Validate Input').first().json;
const mediaId = $json.media_id_string || $json.media_id || null;

return [{
  json: {
    ...validateData,
    mediaId
  }
}];

// Extract Twitter result
const validateData = $('Code - Validate Input').first().json;
const response = $json;
const tweetId = response?.data?.id || null;
const now = new Date().toISOString();

return [{
  json: {
    postId: validateData.postId,
    platform: 'twitter',
    platformPostId: tweetId,
    publishedAt: now,
    status: tweetId ? 'published' : 'failed',
    callbackUrl: validateData.callbackUrl,
    firstComment: validateData.firstComment,
    fullText: validateData.fullText
  }
}];

// Extract Threads result
