// Extract Skool result
// NOTE: Skool does not have a public API. Update this node to match
// your actual Skool integration method (e.g. Zapier, Make, or browser automation).
const validateData = $('Code - Validate Input').first().json;
const response = $json;
const skoolPostId = response?.id || response?.postId || null;
const now = new Date().toISOString();

return [{
  json: {
    postId: validateData.postId,
    platform: 'skool',
    platformPostId: skoolPostId,
    publishedAt: now,
    status: skoolPostId ? 'published' : 'failed',
    callbackUrl: validateData.callbackUrl,
    firstComment: validateData.firstComment,
    fullText: validateData.fullText
  }
}];

// Build Google Sheets update row for published status
const d = $json;
const p = d.platform;
const row = {
  post_id: d.postId
};

row[`${p}_status`] = d.status;
if (d.publishedAt) row[`${p}_published_at`] = d.publishedAt;
if (d.platformPostId) row[`${p}_platform_post_id`] = d.platformPostId;

return [{ json: {
  ...d,
  _sheetRow: row,
  action: 'UPDATE_PLATFORM_VARIANT',
  payload: { postId: d.postId, platform: d.platform, variant: { status: d.status, publishedAt: d.publishedAt || null, platformPostId: d.platformPostId || null } }
} }];

// Restore original publish context from Code - Build Sheet Update Row
// ($input is the sub-workflow output, not the original publish data)
const all = $('Code - Build Sheet Update Row').all();
return all.map(item => ({
  json: {
    postId: item.json.postId,
    platform: item.json.platform,
    platformPostId: item.json.platformPostId,
    publishedAt: item.json.publishedAt,
    status: item.json.status,
    callbackUrl: item.json.callbackUrl,
    firstComment: item.json.firstComment,
    fullText: item.json.fullText
  }
}));

// Build sheet row for first comment status update
const d = $input.first().json;
const platform = d.platform || $('Switch - First Comment Platform').item.json.platform;
const status = d.id || d.data?.id ? 'published' : 'failed';

const postId = $('Code - Restore Context').first().json.postId;
const callbackUrl = $('Code - Restore Context').first().json.callbackUrl;
return [{
  json: {
    postId,
    platform,
    firstCommentStatus: status,
    callbackUrl,
    publishResult: $('Code - Restore Context').first().json,
    action: 'UPDATE_PLATFORM_VARIANT',
    payload: { postId, platform, variant: { firstCommentStatus: status } }
  }
}];

// Build final callback payload
let postId = '';
let platform = '';
let status = 'published';
let callbackUrl = '';

try {
  const ctx = $('Code - Restore Context').first().json;
  postId = ctx.postId;
  platform = ctx.platform;
  status = ctx.status;
  callbackUrl = ctx.callbackUrl;
} catch(e) {
  const inp = $input.first().json;
  postId = inp.postId || inp.publishResult?.postId || '';
  platform = inp.platform || inp.publishResult?.platform || '';
  status = inp.status || 'published';
  callbackUrl = inp.callbackUrl || inp.publishResult?.callbackUrl || '';
}

return [{
  json: { postId, platform, status, callbackUrl }
}];
